import React, { useState } from "react";
import { ethers } from "ethers";
import Web3Modal from "web3modal";
import { CONTRACT_ADDRESS, CONTRACT_ABI } from "../../constants";

export default function IssuerDashboard() {
  const [issuerAddr, setIssuerAddr] = useState("");
  const [target, setTarget] = useState("");
  const [level, setLevel] = useState(1);
  const [validFor, setValidFor] = useState(30); // days
  const [status, setStatus] = useState("");

  const getSignerContract = async () => {
    const web3Modal = new Web3Modal();
    const conn = await web3Modal.connect();
    const provider = new ethers.providers.Web3Provider(conn);
    const signer = provider.getSigner();
    const addr = await signer.getAddress();
    setIssuerAddr(addr);
    return new ethers.Contract(CONTRACT_ADDRESS, CONTRACT_ABI, signer);
  };

  const approve = async () => {
    try {
      const c = await getSignerContract();
      setStatus("Sending tx...");
      const seconds = Number(validFor) * 24 * 60 * 60;
      const tx = await c.approveKyc(target, Number(level), seconds);
      await tx.wait();
      setStatus(`✅ Approved KYC for ${target}`);
    } catch (err) {
      console.error(err);
      setStatus("❌ " + (err.reason || err.message));
    }
  };

  const revoke = async () => {
    try {
      const c = await getSignerContract();
      setStatus("Sending revoke tx...");
      const tx = await c.revokeKyc(target);
      await tx.wait();
      setStatus(`⚠️ Revoked KYC for ${target}`);
    } catch (err) {
      console.error(err);
      setStatus("❌ " + (err.reason || err.message));
    }
  };

  return (
    <div className="card">
      <h2>Issuer Portal</h2>
      <p className="muted">
        Connect with an issuer wallet registered in the contract. Only issuers
        can approve or revoke KYC.
      </p>
      {issuerAddr && (
        <p>
          Issuer: <code>{issuerAddr}</code>
        </p>
      )}
      <input
        type="text"
        placeholder="User address (0x...)"
        value={target}
        onChange={e => setTarget(e.target.value)}
      />
      <label>Level</label>
      <select value={level} onChange={e => setLevel(e.target.value)}>
        <option value={1}>1 - Basic</option>
        <option value={2}>2 - Enhanced</option>
      </select>
      <label>Validity (days)</label>
      <input
        type="number"
        min="1"
        value={validFor}
        onChange={e => setValidFor(e.target.value)}
      />
      <div>
        <button onClick={approve}>Approve / Update KYC</button>
        <button className="secondary" onClick={revoke}>
          Revoke KYC
        </button>
      </div>
      {status && <p>{status}</p>}
    </div>
  );
}
